    +'<span class="mun">MUNIC\u00cdPIO DE '+he((d.mun||'').toUpperCase())+'</span>'
    +tbls
    +'<div class="det">'
    +'<p class="det-titulo">DETERMINA\u00c7\u00c3O:</p>'
