// ═══ DOCX via template real ═══
function b64ToBytes(b64){
  var bin=atob(b64),a=new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++)a[i]=bin.charCodeAt(i);
  return a;
}
function xe(s){
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function mkCell(txt,w,hdr){
  var fill=hdr?'<w:shd w:val="clear" w:color="auto" w:fill="1F3864"/>':'';
  var tcpr='<w:tcPr><w:tcW w:w="'+w+'" w:type="dxa"/>'+fill+'</w:tcPr>';
  var col=hdr?'<w:color w:val="FFFFFF"/>':'';
  var bold=hdr?'<w:b/>':'';
  var rpr='<w:rPr>'+bold+col+'<w:sz w:val="18"/><w:szCs w:val="18"/></w:rPr>';
  var par='<w:p><w:pPr><w:jc w:val="center"/><w:rPr>'+bold+col+'<w:sz w:val="18"/><w:szCs w:val="18"/></w:rPr></w:pPr><w:r>'+rpr+'<w:t xml:space="preserve">'+xe(txt)+'</w:t></w:r></w:p>';
  return '<w:tc>'+tcpr+par+'</w:tc>';
}
var CW=[994,2281,3544,1276,1276,1559];

function mkTurnoXML(t,og,miss){
  var pm='<w:p><w:pPr><w:jc w:val="center"/><w:rPr><w:b/><w:sz w:val="20"/><w:szCs w:val="20"/></w:rPr></w:pPr><w:r><w:rPr><w:b/><w:sz w:val="20"/><w:szCs w:val="20"/></w:rPr><w:t>'+xe(miss)+'</w:t></w:r></w:p>';
  var ph='<w:p><w:pPr><w:jc w:val="center"/><w:rPr><w:b/><w:sz w:val="20"/><w:szCs w:val="20"/><w:highlight w:val="yellow"/></w:rPr></w:pPr><w:r><w:rPr><w:b/><w:sz w:val="20"/><w:szCs w:val="20"/><w:highlight w:val="yellow"/></w:rPr><w:t>'+xe('Horário da escala: '+t.hor)+'</w:t></w:r></w:p>';
  var pl=t.local?'<w:p><w:pPr><w:jc w:val="center"/><w:rPr><w:b/><w:sz w:val="20"/><w:szCs w:val="20"/></w:rPr></w:pPr><w:r><w:rPr><w:b/><w:sz w:val="20"/><w:szCs w:val="20"/></w:rPr><w:t>'+xe(t.local.toUpperCase())+'</w:t></w:r></w:p>':'';
  var tr0='<w:tr><w:trPr><w:trHeight w:val="275"/></w:trPr><w:tc><w:tcPr><w:tcW w:w="10930" w:type="dxa"/><w:gridSpan w:val="6"/><w:vAlign w:val="center"/></w:tcPr>'+pm+ph+pl+'</w:tc></w:tr>';
  var hdrs=['Ordem','Posto/Grad.','Nome Completo','RG','NF','Função'];
  var trh='<w:tr><w:trPr><w:trHeight w:val="275"/></w:trPr>'+hdrs.map(function(h,i){return mkCell(h,CW[i],true);}).join('')+'</w:tr>';
  var trm=t.mils.map(function(m,j){
    var vs=[String(og+j)+'.',m.po,m.no,m.rg,m.nf,m.fu];
    return '<w:tr><w:trPr><w:trHeight w:val="275"/></w:trPr>'+vs.map(function(v,i){return mkCell(v,CW[i],false);}).join('')+'</w:tr>';
  }).join('');
  return '<w:tbl>'+TBL_HDR+tr0+trh+trm+'</w:tbl>';
}

function gerarDocx(d){
  if(!d){var err=validEsc();if(err){alert(err);return;}d=getDados();}
  if(typeof JSZip==='undefined'){alert('JSZip não carregou. Use o botão PDF.');return;}
  var op=APP.ops.find(function(o){return o.nome===d.op;})||{};
  var miss=op.desc||'Fazer saturação nos bairros com planejamento específico de ações repressivas, locais sensíveis com alto índice de violência, tráfico, dentre outros delitos';
  var df=new Date(d.data+'T12:00:00').toLocaleDateString('pt-BR',{day:'2-digit',month:'long',year:'numeric',weekday:'long'}).toUpperCase();
  var dfc=new Date(d.data+'T12:00:00').toLocaleDateString('pt-BR',{day:'2-digit',month:'long',year:'numeric'});
  var cidStr=(d.mun||'Colatina').split('/')[0].trim()+'-ES, '+dfc+'.';

  JSZip.loadAsync(b64ToBytes(TMPL_B64)).then(function(zip){
    return zip.file('word/document.xml').async('string').then(function(xml){

      // ── Título
      xml=xml.replace(/##TITULO##/g, xe('ISEO \u2013 '+d.op));

      // ── Data
      xml=xml.replace(/##DATA##/g, xe(df));

      // ── Município
      xml=xml.replace(/##MUNICIPIO##/g, xe('MUNICÍPIO DE '+(d.mun||'').toUpperCase()));

      // ── Data cidade
      xml=xml.replace(/##DATACIDADE##/g, xe(cidStr));

      // ── Assinante
      xml=xml.replace(/##ASSNAME##/g, xe(d.an));
      xml=xml.replace(/##ASSCARGO##/g, xe(d.ar+' - '+d.ac));

      // ── Tabela(s) — substituir o bloco <w:tbl>...</w:tbl> existente
      var og=1;
      var novasTbl='';
      d.turnos.forEach(function(t){
        if(!t.mils||!t.mils.length)return;
        novasTbl+=mkTurnoXML(t,og,miss);
        og+=t.mils.length;
      });
      // Substituir primeira (e única) tabela do template pelos turnos
      xml=xml.replace(/<w:tbl>[\s\S]*?<\/w:tbl>/, novasTbl);

      zip.file('word/document.xml',xml);
      return zip.generateAsync({type:'blob',mimeType:'application/vnd.openxmlformats-officedocument.wordprocessingml.document'});
    });
  }).then(function(blob){
    var url=URL.createObjectURL(blob);
    var a=document.createElement('a');
    a.href=url;
    a.download='ISEO_'+d.op.replace(/\s+/g,'_')+'_'+d.data+'.docx';
    a.click();
    URL.revokeObjectURL(url);
  }).catch(function(e){
    console.error(e);
    if(confirm('Erro ao gerar DOCX: '+e.message+'\n\nGerar PDF em vez disso?'))gerarPDF(d);
  });
}


